```fortran
rogram main
    real(4) :: xpt(1, 1)
    call rescue(xpt)

contains
    subroutine rescue(xpt)
        real(4), intent(inout) :: xpt(:, :)  ! Explicitly declare xpt as (1, 1)
        real(4) :: sum_sq
        integer :: i, j
        sum_sq = 0.0
        do i = 1, size(xpt, dim=1)
            do j = 1, size(xpt, dim=2)
                sum_sq = sum_sq + xpt(i, j)**2  ! Square each element and accumulate
            end do
        end do
        print *, sqrt(sum_sq)
    end subroutine
end program
